proof fn phi_2_filter_len_leq_original(s: Seq<int>, pred: spec_fn(int) -> bool)
    ensures
        s.filter(pred).len() <= s.len(),
    decreases s.len(),
{
    reveal(Seq::filter);
    if s.len() != 0 {
        phi_2_filter_len_leq_original(s.drop_last(), pred);
    }
}

